/**
 * Returns a list of all users.
The users are returned sorted by creation date, with the newest users appearing first.
 * @summary List all users
 */
export const getUserListQueryLimitDefault = 10;
export const getUserListQueryLimitMax = 500;

export const getUserListQueryOffsetDefault = 0;
export const getUserListQueryOffsetMin = 0;

export const getUserListQueryOrderByDefault = `-created_at`;

export const GetUserListQueryParams = zod.object({
  "email_address": zod.array(zod.string()).optional().describe('Returns users with the specified email addresses.\nAccepts up to 100 email addresses.\nAny email addresses not found are ignored.'),
  "phone_number": zod.array(zod.string()).optional().describe('Returns users with the specified phone numbers.\nAccepts up to 100 phone numbers.\nAny phone numbers not found are ignored.'),
  "external_id": zod.array(zod.string()).optional().describe('Returns users with the specified external IDs.\nFor each external ID, the `+` and `-` can be\nprepended to the ID, which denote whether the\nrespective external ID should be included or\nexcluded from the result set.\nAccepts up to 100 external IDs.\nAny external IDs not found are ignored.'),
  "username": zod.array(zod.string()).optional().describe('Returns users with the specified usernames.\nAccepts up to 100 usernames.\nAny usernames not found are ignored.'),
  "web3_wallet": zod.array(zod.string()).optional().describe('Returns users with the specified web3 wallet addresses.\nAccepts up to 100 web3 wallet addresses.\nAny web3 wallet addresses not found are ignored.'),
  "user_id": zod.array(zod.string()).optional().describe('Returns users with the user IDs specified.\nFor each user ID, the `+` and `-` can be\nprepended to the ID, which denote whether the\nrespective user ID should be included or\nexcluded from the result set.\nAccepts up to 100 user IDs.\nAny user IDs not found are ignored.'),
  "organization_id": zod.array(zod.string()).optional().describe('Returns users that have memberships to the\ngiven organizations.\nFor each organization ID, the `+` and `-` can be\nprepended to the ID, which denote whether the\nrespective organization should be included or\nexcluded from the result set.\nAccepts up to 100 organization IDs.'),
  "query": zod.string().optional().describe('Returns users that match the given query.\nFor possible matches, we check the email addresses, phone numbers, usernames, web3 wallets, user IDs, first and last names.\nThe query value doesn\'t need to match the exact value you are looking for, it is capable of partial matches as well.'),
  "email_address_query": zod.string().optional().describe('Returns users with emails that match the given query, via case-insensitive partial match.\nFor example, `email_address_query=ello` will match a user with the email `HELLO@example.com`.'),
  "phone_number_query": zod.string().optional().describe('Returns users with phone numbers that match the given query, via case-insensitive partial match.\nFor example, `phone_number_query=555` will match a user with the phone number `+1555xxxxxxx`.'),
  "username_query": zod.string().optional().describe('Returns users with usernames that match the given query, via case-insensitive partial match.\nFor example, `username_query=CoolUser` will match a user with the username `SomeCoolUser`.'),
  "name_query": zod.string().optional().describe('Returns users with names that match the given query, via case-insensitive partial match.'),
  "banned": zod.boolean().optional().describe('Returns users which are either banned (`banned=true`) or not banned (`banned=false`).'),
  "last_active_at_before": zod.number().optional().describe('Returns users whose last session activity was before the given date (with millisecond precision).\nExample: use 1700690400000 to retrieve users whose last session activity was before 2023-11-23.'),
  "last_active_at_after": zod.number().optional().describe('Returns users whose last session activity was after the given date (with millisecond precision).\nExample: use 1700690400000 to retrieve users whose last session activity was after 2023-11-23.'),
  "last_active_at_since": zod.number().optional().describe('Returns users that had session activity since the given date.\nExample: use 1700690400000 to retrieve users that had session activity from 2023-11-23 until the current day.\nDeprecated in favor of `last_active_at_after`.'),
  "created_at_before": zod.number().optional().describe('Returns users who have been created before the given date (with millisecond precision).\nExample: use 1730160000000 to retrieve users who have been created before 2024-10-29.'),
  "created_at_after": zod.number().optional().describe('Returns users who have been created after the given date (with millisecond precision).\nExample: use 1730160000000 to retrieve users who have been created after 2024-10-29.'),
  "last_sign_in_at_before": zod.number().optional().describe('Returns users whose last sign-in was before the given date (with millisecond precision).\nExample: use 1700690400000 to retrieve users whose last sign-in was before 2023-11-23.'),
  "last_sign_in_at_after": zod.number().optional().describe('Returns users whose last sign-in was after the given date (with millisecond precision).\nExample: use 1700690400000 to retrieve users whose last sign-in was after 2023-11-23.'),
  "provider": zod.string().optional().describe('Returns users with external accounts for the specified OAuth provider.\nMust be used in combination with the `provider_user_id` parameter.\nFor example, use `provider=oauth_google&provider_user_id=12345` to retrieve a user with Google provider user ID 12345.'),
  "provider_user_id": zod.array(zod.string()).optional().describe('Returns users with the specified provider user IDs for a specific provider.\nMust be used in combination with the `provider` parameter.\nFor example, use `provider=oauth_google&provider_user_id=12345` to retrieve a user with Google provider user ID 12345.\nAccepts up to 100 provider user IDs.\nAny provider user IDs not found are ignored.'),
  "limit": zod.number().min(1).max(getUserListQueryLimitMax).default(getUserListQueryLimitDefault).describe('Applies a limit to the number of results returned.\nCan be used for paginating the results together with `offset`.'),
  "offset": zod.number().min(getUserListQueryOffsetMin).default(getUserListQueryOffsetDefault).describe('Skip the first `offset` results when paginating.\nNeeds to be an integer greater or equal to zero.\nTo be used in conjunction with `limit`.'),
  "order_by": zod.string().default(getUserListQueryOrderByDefault).describe('Allows to return users in a particular order.\nAt the moment, you can order the returned users by their `created_at`,`updated_at`,`email_address`,`web3wallet`,`first_name`,`last_name`,`phone_number`,`username`,`last_active_at`,`last_sign_in_at`.\nIn order to specify the direction, you can use the `+\/-` symbols prepended in the property to order by.\nFor example, if you want users to be returned in descending order according to their `created_at` property, you can use `-created_at`.\nIf you don\'t use `+` or `-`, then `+` is implied. We only support one `order_by` parameter, and if multiple `order_by` parameters are provided, we will only keep the first one. For example,\nif you pass `order_by=username&order_by=created_at`, we will consider only the first `order_by` parameter, which is `username`. The `created_at` parameter will be ignored in this case.')
})

