/**
 * Returns a total count of all users that match the given filtering criteria.
 * @summary Count users
 */
export const GetUsersCountQueryParams = zod.object({
  "email_address": zod.array(zod.string()).optional().describe('Counts users with the specified email addresses.\nAccepts up to 100 email addresses.\nAny email addresses not found are ignored.'),
  "phone_number": zod.array(zod.string()).optional().describe('Counts users with the specified phone numbers.\nAccepts up to 100 phone numbers.\nAny phone numbers not found are ignored.'),
  "external_id": zod.array(zod.string()).optional().describe('Counts users with the specified external IDs.\nAccepts up to 100 external IDs.\nAny external IDs not found are ignored.'),
  "username": zod.array(zod.string()).optional().describe('Counts users with the specified usernames.\nAccepts up to 100 usernames.\nAny usernames not found are ignored.'),
  "web3_wallet": zod.array(zod.string()).optional().describe('Counts users with the specified web3 wallet addresses.\nAccepts up to 100 web3 wallet addresses.\nAny web3 wallet addresses not found are ignored.'),
  "user_id": zod.array(zod.string()).optional().describe('Counts users with the user IDs specified.\nAccepts up to 100 user IDs.\nAny user IDs not found are ignored.'),
  "organization_id": zod.array(zod.string()).optional().describe('Returns users that have memberships to the given organizations. For each organization ID, the `+` and `-`\ncan be prepended to the ID, which denote whether the respective organization should be included or\nexcluded from the result set. Accepts up to 100 organization IDs.'),
  "query": zod.string().optional().describe('Counts users that match the given query.\nFor possible matches, we check the email addresses, phone numbers, usernames, web3 wallets, user IDs, first and last names.\nThe query value doesn\'t need to match the exact value you are looking for, it is capable of partial matches as well.'),
  "email_address_query": zod.string().optional().describe('Counts users with emails that match the given query, via case-insensitive partial match.\nFor example, `email_address_query=ello` will match a user with the email `HELLO@example.com`,\nand will be included in the resulting count.'),
  "phone_number_query": zod.string().optional().describe('Counts users with phone numbers that match the given query, via case-insensitive partial match.\nFor example, `phone_number_query=555` will match a user with the phone number `+1555xxxxxxx`,\nand will be included in the resulting count.'),
  "username_query": zod.string().optional().describe('Counts users with usernames that match the given query, via case-insensitive partial match.\nFor example, `username_query=CoolUser` will match a user with the username `SomeCoolUser`,\nand will be included in the resulting count.'),
  "name_query": zod.string().optional().describe('Returns users with names that match the given query, via case-insensitive partial match.'),
  "banned": zod.boolean().optional().describe('Counts users which are either banned (`banned=true`) or not banned (`banned=false`).'),
  "last_active_at_before": zod.number().optional().describe('Returns users whose last session activity was before the given date (with millisecond precision).\nExample: use 1700690400000 to retrieve users whose last session activity was before 2023-11-23.'),
  "last_active_at_after": zod.number().optional().describe('Returns users whose last session activity was after the given date (with millisecond precision).\nExample: use 1700690400000 to retrieve users whose last session activity was after 2023-11-23.'),
  "last_active_at_since": zod.number().optional().describe('Returns users that had session activity since the given date.\nExample: use 1700690400000 to retrieve users that had session activity from 2023-11-23 until the current day.\nDeprecated in favor of `last_active_at_after`.'),
  "created_at_before": zod.number().optional().describe('Returns users who have been created before the given date (with millisecond precision).\nExample: use 1730160000000 to retrieve users who have been created before 2024-10-29.'),
  "created_at_after": zod.number().optional().describe('Returns users who have been created after the given date (with millisecond precision).\nExample: use 1730160000000 to retrieve users who have been created after 2024-10-29.'),
  "last_sign_in_at_before": zod.number().optional().describe('Counts users whose last sign-in was before the given date (with millisecond precision).\nExample: use 1700690400000 to count users whose last sign-in was before 2023-11-23.'),
  "last_sign_in_at_after": zod.number().optional().describe('Counts users whose last sign-in was after the given date (with millisecond precision).\nExample: use 1700690400000 to count users whose last sign-in was after 2023-11-23.'),
  "provider": zod.string().optional().describe('Counts users with external accounts for the specified OAuth provider.\nMust be used in combination with the `provider_user_id` parameter.\nFor example, use `provider=oauth_google&provider_user_id=12345` to count users with Google provider user ID 12345.\nAccepts up to 100 providers.'),
  "provider_user_id": zod.array(zod.string()).optional().describe('Counts users with the specified provider user IDs for a specific provider.\nMust be used in combination with the `provider` parameter.\nFor example, use `provider=oauth_google&provider_user_id=12345` to count users with Google provider user ID 12345.\nAccepts up to 100 provider user IDs.\nAny provider user IDs not found are ignored.')
})

