/**
 * Creates a new organization invitation and sends an email to the provided `email_address` with a link to accept the invitation and join the organization.
You can specify the `role` for the invited organization member.

New organization invitations get a "pending" status until they are revoked by an organization administrator or accepted by the invitee.

The request body supports passing an optional `redirect_url` parameter.
When the invited user clicks the link to accept the invitation, they will be redirected to the URL provided.
Use this parameter to implement a custom invitation acceptance flow.

You can specify the ID of the user that will send the invitation with the `inviter_user_id` parameter.
That user must be a member with administrator privileges in the organization.
Only "admin" members can create organization invitations.

You can optionally provide public and private metadata for the organization invitation.
The public metadata are visible by both the Frontend and the Backend whereas the private ones only by the Backend.
When the organization invitation is accepted, the metadata will be transferred to the newly created organization membership.
 * @summary Create and send an organization invitation
 */
export const CreateOrganizationInvitationParams = zod.object({
  "organization_id": zod.string().describe('The ID of the organization for which to send the invitation')
})

export const createOrganizationInvitationBodyExpiresInDaysMax = 365;

export const createOrganizationInvitationBodyNotifyDefault = true;

export const CreateOrganizationInvitationBody = zod.object({
  "email_address": zod.string().describe('The email address of the new member that is going to be invited to the organization'),
  "inviter_user_id": zod.string().nullish().describe('The ID of the user that invites the new member to the organization.\nMust be an administrator in the organization.'),
  "role": zod.string().describe('The role of the new member in the organization'),
  "public_metadata": zod.record(zod.string(), zod.unknown()).nullish().describe('Metadata saved on the organization invitation, read-only from the Frontend API and fully accessible (read\/write) from the Backend API.\nWhen the organization invitation is accepted, the metadata will be transferred to the newly created organization membership.'),
  "private_metadata": zod.record(zod.string(), zod.unknown()).nullish().describe('Metadata saved on the organization invitation, fully accessible (read\/write) from the Backend API but not visible from the Frontend API.\nWhen the organization invitation is accepted, the metadata will be transferred to the newly created organization membership.'),
  "redirect_url": zod.string().nullish().describe('Optional URL that the invitee will be redirected to once they accept the invitation by clicking the join link in the invitation email.'),
  "expires_in_days": zod.number().min(1).max(createOrganizationInvitationBodyExpiresInDaysMax).nullish().describe('The number of days the invitation will be valid for. By default, the invitation has a 30 days expire.'),
  "notify": zod.boolean().nullish().default(createOrganizationInvitationBodyNotifyDefault).describe('Optional flag which denotes whether an email invitation should be sent to the given email address.\nDefaults to `true`.')
})

