export const getM2MTokensQueryOffsetDefault = 0;
export const getM2MTokensQueryOffsetMin = 0;



export const GetM2MTokensQueryParams = zod.object({
  "subject": zod.string().regex(getM2MTokensQuerySubjectRegExp),
  "revoked": zod.boolean().nullish().default(getM2MTokensQueryRevokedDefault),
  "expired": zod.boolean().nullish().default(getM2MTokensQueryExpiredDefault),
  "limit": zod.number().min(1).max(getM2MTokensQueryLimitMax).default(getM2MTokensQueryLimitDefault),
  "offset": zod.number().min(getM2MTokensQueryOffsetMin).nullish().default(getM2MTokensQueryOffsetDefault)
})

export const getM2MTokensResponseM2mTokensItemIdRegExp = new RegExp('^mt_[0-9A-Fa-f]{32}$');
export const getM2MTokensResponseM2mTokensItemSubjectRegExp = new RegExp('^mch_\\w{27}$');
export const getM2MTokensResponseM2mTokensItemScopesItemRegExp = new RegExp('^mch_\\w{27}$');
export const getM2MTokensResponseM2mTokensItemScopesDefault = [];

export const GetM2MTokensResponse = zod.object({
  "m2m_tokens": zod.array(zod.object({
  "object": zod.enum(['machine_to_machine_token']),
  "id": zod.string().regex(getM2MTokensResponseM2mTokensItemIdRegExp),
  "subject": zod.string().regex(getM2MTokensResponseM2mTokensItemSubjectRegExp),
  "claims": zod.unknown().nullish(),
  "scopes": zod.array(zod.string().regex(getM2MTokensResponseM2mTokensItemScopesItemRegExp)).default(getM2MTokensResponseM2mTokensItemScopesDefault),
  "revoked": zod.boolean(),
  "revocation_reason": zod.string().nullable(),
  "expired": zod.boolean(),
  "expiration": zod.number().nullable().describe('The timestamp for when the token will expire, in milliseconds'),
  "last_used_at": zod.number().nullable().describe('The timestamp for when the token was last used, in milliseconds'),
  "created_at": zod.number().describe('The timestamp for when the token was created, in milliseconds'),
  "updated_at": zod.number().describe('The timestamp for when the token was last updated, in milliseconds')
})),
  "total_count": zod.number()
})


/**
 * Revokes a M2M Token.

This endpoint only revokes stored opaque-format M2M tokens. JWT-format M2M tokens are stateless and cannot be revoked.

This endpoint can be authenticated by either a Machine Secret Key or by a Clerk Secret Key.

- When revoking a M2M Token with a Machine Secret Key, the token must managed by the Machine associated with the Machine Secret Key.
- When revoking a M2M Token with a Clerk Secret Key, any token on the Instance can be revoked.
 * @summary Revoke a M2M Token
 */
export const revokeM2MTokenPathM2mTokenIdRegExp = new RegExp('^mt_[0-9A-Fa-f]{32}$');


export const RevokeM2MTokenParams = zod.object({
  "m2m_token_id": zod.string().regex(revokeM2MTokenPathM2mTokenIdRegExp)
})

export const RevokeM2MTokenBody = zod.object({
  "revocation_reason": zod.string().nullish()
})

export const revokeM2MTokenResponseIdRegExp = new RegExp('^mt_[0-9A-Fa-f]{32}$');
export const revokeM2MTokenResponseSubjectRegExp = new RegExp('^mch_\\w{27}$');
export const revokeM2MTokenResponseScopesItemRegExp = new RegExp('^mch_\\w{27}$');
export const revokeM2MTokenResponseScopesDefault = [];

export const RevokeM2MTokenResponse = zod.object({
  "object": zod.enum(['machine_to_machine_token']),
  "id": zod.string().regex(revokeM2MTokenResponseIdRegExp),
  "subject": zod.string().regex(revokeM2MTokenResponseSubjectRegExp),
  "claims": zod.unknown().nullish(),
  "scopes": zod.array(zod.string().regex(revokeM2MTokenResponseScopesItemRegExp)).default(revokeM2MTokenResponseScopesDefault),
  "revoked": zod.boolean(),
  "revocation_reason": zod.string().nullable(),
  "expired": zod.boolean(),
  "expiration": zod.number().nullable().describe('The timestamp for when the token will expire, in milliseconds'),
  "last_used_at": zod.number().nullable().describe('The timestamp for when the token was last used, in milliseconds'),
  "created_at": zod.number().describe('The timestamp for when the token was created, in milliseconds'),
  "updated_at": zod.number().describe('The timestamp for when the token was last updated, in milliseconds')
})


/**
 * Verifies a M2M Token.

This endpoint can be authenticated by either a Machine Secret Key or by a Clerk Secret Key.

- When verifying a M2M Token with a Machine Secret Key, the token must be granted access to the Machine associated with the Machine Secret Key.
- When verifying a M2M Token with a Clerk Secret Key, any token on the Instance can be verified.
 * @summary Verify a M2M Token
 */
export const VerifyM2MTokenBody = zod.object({
  "token": zod.string()
})

export const verifyM2MTokenResponseIdRegExp = new RegExp('^mt_[0-9A-Fa-f]{32}$');
export const verifyM2MTokenResponseSubjectRegExp = new RegExp('^mch_\\w{27}$');
export const verifyM2MTokenResponseScopesItemRegExp = new RegExp('^mch_\\w{27}$');
export const verifyM2MTokenResponseScopesDefault = [];

export const VerifyM2MTokenResponse = zod.object({
  "object": zod.enum(['machine_to_machine_token']),
  "id": zod.string().regex(verifyM2MTokenResponseIdRegExp),
  "subject": zod.string().regex(verifyM2MTokenResponseSubjectRegExp),
  "claims": zod.unknown().nullish(),
  "scopes": zod.array(zod.string().regex(verifyM2MTokenResponseScopesItemRegExp)).default(verifyM2MTokenResponseScopesDefault),
  "revoked": zod.boolean(),
  "revocation_reason": zod.string().nullable(),
  "expired": zod.boolean(),
  "expiration": zod.number().nullable().describe('The timestamp for when the token will expire, in milliseconds'),
  "last_used_at": zod.number().nullable().describe('The timestamp for when the token was last used, in milliseconds'),
  "created_at": zod.number().describe('The timestamp for when the token was created, in milliseconds'),
  "updated_at": zod.number().describe('The timestamp for when the token was last updated, in milliseconds')
})


/**
 * @summary Verify an OAuth Access Token
 */
export const VerifyOAuthAccessTokenBody = zod.object({
  "access_token": zod.string().optional().describe('The access token to verify.'),
  "secret": zod.string().optional().describe('The access token to verify. This is deprecated, use `access_token` instead.')
})

export const verifyOAuthAccessTokenResponseOneIdRegExp = new RegExp('^oat_[0-9A-Fa-f]{32}$');
export const verifyOAuthAccessTokenResponseOneSubjectRegExp = new RegExp('^user_\\w{27}$');


export const VerifyOAuthAccessTokenResponse = zod.union([zod.object({
  "object": zod.enum(['clerk_idp_oauth_access_token']),
  "id": zod.string().regex(verifyOAuthAccessTokenResponseOneIdRegExp),
  "client_id": zod.string(),
  "subject": zod.string().regex(verifyOAuthAccessTokenResponseOneSubjectRegExp),
  "scopes": zod.array(zod.string()),
  "revoked": zod.boolean(),
  "revocation_reason": zod.string().nullable(),
  "expired": zod.boolean(),
  "expiration": zod.number().nullable(),
  "created_at": zod.number(),
  "updated_at": zod.number()
}),zod.object({
  "active": zod.literal(false).describe('Indicates that a JWT access token is not active (expired)')
})])
